import React, { useEffect, useState, useContext } from 'react';
import api from '../api/axiosConfig';
import { AuthContext } from '../context/AuthContext';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X, BarChart } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const { token } = useContext(AuthContext);
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  const safeParseHoldings = (data) => {
    if (!data) return [];
    try {
      let parsed = typeof data === 'string' ? JSON.parse(data) : data;
      if (typeof parsed === 'string') parsed = JSON.parse(parsed);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) { return []; }
  };

  const fetchHistory = async () => {
    try {
      const res = await api.get('/portfolio/history');
      setHistory(res.data);
    } catch (err) {
      toast.error("VAULT_SYNC_FAILURE");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("PERMANENT_WIPE: Delete this strategy?")) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success("STRATEGY_DELETED");
    } catch (err) {
      toast.error("WIPE_FAILED");
    }
  };

  const handleDownload = async (item) => {
    try {
      const response = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Finify_Strategy_${item.id}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (err) {
      toast.error("PDF_SYNTHESIS_FAILED");
    }
  };

  useEffect(() => { fetchHistory(); }, []);

  if (loading) return <div style={centerStyle}>SYNCHRONIZING_VAULT...</div>;

  return (
    <div className="reveal-node" style={containerStyle}>
      <div style={headerRow}>
        <h2 style={headerStyle}>
          <Archive size={22} color="var(--accent-primary)"/> 
          STRATEGY_VAULT
        </h2>
        <div style={vaultStats}>
          <BarChart size={12} /> {history.length} ACTIVE_NODES
        </div>
      </div>
      
      {history.length === 0 ? (
        <div style={emptyStyle}>
          <p>VAULT_EMPTY: NO_STRATEGIES_INDEXED</p>
          <button onClick={() => window.location.href='/generate'} style={initBtn}>INITIALIZE_NEW_PROMPT</button>
        </div>
      ) : (
        <div style={listStyle}>
          {history.map((item) => (
            <div key={item.id} className="vault-card" style={cardStyle}>
              <div style={{ flex: 1 }}>
                <div style={tagRow}>
                  <span style={dateTag}><Calendar size={10}/> {new Date(item.created_at).toLocaleDateString()}</span>
                  <span style={riskTag}><ShieldCheck size={10}/> RISK_SCORE: {item.risk_score}</span>
                </div>
                <h4 style={titleStyle}>{item.goal}</h4>
                
                <div style={tickerRow}>
                   {safeParseHoldings(item.holdings).map((t, i) => (
                     <span key={i} style={tickerTag}>{t}</span>
                   ))}
                </div>
              </div>

              <div style={actionRow}>
                <button onClick={() => setSelectedItem(item)} style={iconBtn} title="View"><Eye size={18}/></button>
                <button onClick={() => handleDownload(item)} style={iconBtn} title="PDF"><Download size={18}/></button>
                <button onClick={() => handleDelete(item.id)} style={deleteBtn} title="Wipe"><Trash2 size={18}/></button>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* --- MODAL CSS FIX --- */}
      {selectedItem && (
        <div style={modalOverlay}>
          <div style={modalContent}>
            <div style={modalHeader}>
              <span style={{fontFamily: 'monospace', fontSize: '0.7rem'}}>PREVIEW // ID_{selectedItem.id}</span>
              <button onClick={() => setSelectedItem(null)} style={closeBtn}><X size={20}/></button>
            </div>
            <div style={modalBody}>
              <h3 style={modalGoal}>{selectedItem.goal}</h3>
              <p style={sectionLabel}>MARKET_THESIS</p>
              <p style={modalText}>{selectedItem.summary}</p>
              <div style={divider}/>
              <p style={sectionLabel}>AGENTIC_RATIONALE</p>
              <p style={modalText}>{selectedItem.rationale}</p>
            </div>
          </div>
        </div>
      )}

      <style>{`
        .vault-card:hover {
          border-color: var(--accent-primary) !important;
          transform: translateY(-2px);
          box-shadow: 0 8px 30px rgba(0,0,0,0.4);
        }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .reveal-node { animation: fadeIn 0.5s ease forwards; }
      `}</style>
    </div>
  );
};

/* --- REFINED CSS OBJECTS --- */
const containerStyle = { padding: '3rem 2rem', maxWidth: '1100px', margin: '0 auto', color: 'var(--text-primary)' };
